-- ============================================
-- Nourish v2.2 — Moroccan Foods Seed
-- Drops the old foods table and recreates it with 386 curated
-- Moroccan-context foods including proper trilingual labels,
-- Moroccan dialect synonyms, accurate macros, and priority ranking.
-- ============================================

-- Drop existing foods table (recreates cleanly)
DROP TABLE IF EXISTS foods CASCADE;

CREATE TABLE foods (
  id TEXT PRIMARY KEY,
  label_en TEXT NOT NULL,
  label_fr TEXT NOT NULL,
  label_ar TEXT NOT NULL,
  category TEXT NOT NULL,
  category_fr TEXT NOT NULL,
  category_ar TEXT NOT NULL,
  variant TEXT DEFAULT 'raw',
  source TEXT DEFAULT 'moroccan',      -- 'moroccan' | 'off' (for packaged items later)
  priority INTEGER DEFAULT 50,          -- higher = ranks first in search results
  synonyms TEXT[] DEFAULT ARRAY[]::TEXT[],
  calories REAL DEFAULT 0,
  protein REAL DEFAULT 0,
  fat REAL DEFAULT 0,
  carbs REAL DEFAULT 0,
  fiber REAL DEFAULT 0,
  iron REAL DEFAULT 0,
  zinc REAL DEFAULT 0,
  vitamin_c REAL DEFAULT 0,
  folate REAL DEFAULT 0,
  vitamin_b12 REAL DEFAULT 0,
  selenium REAL DEFAULT 0,
  iodine REAL DEFAULT 0,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Indexes for fast search
CREATE INDEX idx_foods_label_en ON foods USING gin (to_tsvector('english', label_en));
CREATE INDEX idx_foods_label_fr ON foods (label_fr);
CREATE INDEX idx_foods_label_ar ON foods (label_ar);
CREATE INDEX idx_foods_category ON foods (category);
CREATE INDEX idx_foods_source_priority ON foods (source, priority DESC);
CREATE INDEX idx_foods_synonyms ON foods USING gin (synonyms);

-- RLS: public read
ALTER TABLE foods ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Foods are readable by all" ON foods FOR SELECT USING (true);

